        if (Lazy.class.equals(typeToCheck)) {
          throw new IllegalStateException("@Provides method must not return Lazy directly: "
              + c.getName()
              + "."
              + method.getName());
        }

        String key = Keys.get(genericReturnType, method.getAnnotations(), method);
