          case UNIQUE:
            handleBindings(bindings, method, key);
            break;
          case SET:
            handleSetBindings(bindings, method, key);
            break;
          default:
            throw new AssertionError("Unknown @Provides type " + provides.type());
        }
      }
    }
  }
